CREATE TABLE visitors(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,visitor_code CHAR(4) NOT NULL UNIQUE,calculator_data JSON NOT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,return_count INT UNSIGNED DEFAULT 0,last_user_agent VARCHAR(500));
CREATE TABLE visitor_events(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,visitor_id BIGINT UNSIGNED NULL,visitor_code CHAR(4),event_type VARCHAR(30) NOT NULL,event_data JSON NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,INDEX(visitor_id),INDEX(visitor_code),INDEX(event_type),CONSTRAINT fk_event_visitor FOREIGN KEY(visitor_id) REFERENCES visitors(id) ON DELETE SET NULL);
CREATE TABLE system_settings(setting_key VARCHAR(100) PRIMARY KEY,setting_value LONGTEXT NOT NULL,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
